import redis.asyncio as redis
from fastapi import FastAPI, Depends, HTTPException, status, Header
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials
from typing import Optional, Dict, Any
import json
from datetime import datetime

app = FastAPI(title="OAuth 2.0 Protected API")

REDIS_HOST = "localhost"
REDIS_PORT = 6379
REDIS_DB = 0
REDIS_PASSWORD = None

redis_client: Optional[redis.Redis] = None

security = HTTPBearer()


async def get_redis_client() -> redis.Redis:
    global redis_client
    if redis_client is None:
        redis_client = redis.Redis(
            host=REDIS_HOST,
            port=REDIS_PORT,
            db=REDIS_DB,
            password=REDIS_PASSWORD,
            decode_responses=True,
            socket_keepalive=True,
            socket_connect_timeout=5
        )
    return redis_client


@app.on_event("startup")
async def startup_event():
    global redis_client
    redis_client = await get_redis_client()
    await redis_client.ping()


@app.on_event("shutdown")
async def shutdown_event():
    if redis_client:
        await redis_client.close()


class TokenValidator:
    def __init__(self, redis_client: redis.Redis):
        self.redis_client = redis_client
    
    async def validate_token(self, token: str) -> Dict[str, Any]:
        token_data = await self.redis_client.get(f"token:{token}")
        
        if not token_data:
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail="Invalid or expired token",
                headers={"WWW-Authenticate": "Bearer"},
            )
        
        try:
            token_info = json.loads(token_data)
            return token_info
        except json.JSONDecodeError:
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail="Malformed token data",
                headers={"WWW-Authenticate": "Bearer"},
            )
    
    async def validate_token_with_scopes(self, token: str, required_scopes: list[str]) -> Dict[str, Any]:
        token_info = await self.validate_token(token)
        
        token_scopes = token_info.get("scopes", [])
        
        for scope in required_scopes:
            if scope not in token_scopes:
                raise HTTPException(
                    status_code=status.HTTP_403_FORBIDDEN,
                    detail=f"Insufficient permissions. Required scope: {scope}",
                )
        
        return token_info


async def get_token_validator(redis_client: redis.Redis = Depends(get_redis_client)) -> TokenValidator:
    return TokenValidator(redis_client)


async def get_current_user(
    credentials: HTTPAuthorizationCredentials = Depends(security),
    validator: TokenValidator = Depends(get_token_validator)
) -> Dict[str, Any]:
    token = credentials.credentials
    token_info = await validator.validate_token(token)
    return token_info


async def get_current_user_with_scopes(required_scopes: list[str]):
    async def _get_current_user_with_scopes(
        credentials: HTTPAuthorizationCredentials = Depends(security),
        validator: TokenValidator = Depends(get_token_validator)
    ) -> Dict[str, Any]:
        token = credentials.credentials
        token_info = await validator.validate_token_with_scopes(token, required_scopes)
        return token_info
    
    return _get_current_user_with_scopes


async def validate_bearer_token_header(
    authorization: Optional[str] = Header(None),
    validator: TokenValidator = Depends(get_token_validator)
) -> Dict[str, Any]:
    if not authorization:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Authorization header missing",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    parts = authorization.split()
    
    if len(parts) != 2 or parts[0].lower() != "bearer":
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid authorization header format. Expected: Bearer <token>",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    token = parts[1]
    token_info = await validator.validate_token(token)
    return token_info


